def get_user_city(user_dict):
    return user_dict['address']['city']

def main():
    users = [
        {'name': 'Alice', 'address': {'city': 'NYC'}},
        {'name': 'Bob'},
        {'name': 'Carol', 'address': {'city': 'LA'}},
        {'name': 'Dave', 'address': {}},
    ]
    results = []
    for u in users:
        try:
            city = get_user_city(u)
            results.append(city)
        except (KeyError, TypeError):
            results.append('Unknown')
    assert results == ['NYC', 'Unknown', 'LA', 'Unknown'], f'Failed: {results}'
    print('PASSED')

if __name__ == '__main__':
    main()

files.stats.py:
def mean(numbers):
    return sum(numbers) / len(numbers)

def median(numbers):
    s = sorted(numbers)
    n = len(s)
    mid = n // 2
    if n % 2 == 0:
        return (s[mid] + s[mid + 1]) / 2  # BUG: should be s[mid-1]
    return s[mid]

def clamp(value, lo, hi):
    if value < lo:
        return lo
    if value > hi:
        return value  # BUG: should return hi
    return value

def normalize(numbers):
    mn = min(numbers)
    mx = max(numbers)
    return [(x - mn) / (mx - mn) for x in numbers]  # BUG: will crash on all-same list

if __name__ == '__main__':
    assert mean([1, 2, 3, 4, 5]) == 3.0
    assert median([1, 2, 3, 4]) == 2.5
    assert clamp(15, 0, 10) == 10
    assert normalize([5, 5, 5]) == [0.0, 0.0, 0.0]
    print('All assertions passed')

